class IndentationIssueTest {
    private val indentationRuleAssertThat = assertThatRule { IndentationRule() }

    @Test
    fun `issue reproduction - unexpected indentation of closing parenthesis in if expression`() {
        val code =
            """
            val pass = if (condition1) {
                (
                    condition2
                )
            } else {
                condition3
            }
            """.trimIndent()
        indentationRuleAssertThat(code)
            .withEditorConfigOverride(CODE_STYLE_PROPERTY to ktlint_official)
            .hasNoLintViolations()
    }

